public String zipZap(String str)
{
    for (int i = 0; i < str.length() - 2; i++) 
    {
    if (str.charAt(i) == 'z' && str.charAt(i + 2) == 'p')
    {
        str.replace(str.substring(i + 1), "");
    }
    }
    return str;
}

public String alarmClock(int day, boolean vacation)
{
    if (vacation) { 
        if (day == 0 || day == 6) {
            return "off";
        } else {
            return "10:00";
        }
    } else {
        if (day == 0 || day == 6) {
            return "10:00";
        } else {
            return "7:00";
        }
    }
}

public String alarmClock(int day, boolean vacation)
{
    while (vacation == false)
    {
        if (day >= 1 && day <= 5)
        {
            return "7:00";
        }
        else
        {
            return "10:00";
        }
    }
    while (vacation == true)
    {
        if (day >= 1 && day <= 5)
        {
            return "10:00";
        }
        else
        {
            return "off";
        }
    }
    return "off";
}

